def wait_futures(futures: Dict, timeout_s: float, quiet: bool = False) -> Tuple[bool, List[str]]:
    ok = True
    errs: List[str] = []
    deadline = time.time() + timeout_s
    for k, f in futures.items():
        remaining = max(0.1, deadline - time.time())
        try:
            f.result(timeout=remaining)
            if not quiet:
                eprint(f"OK: {k}")
        except Exception as ex:
            ok = False
            msg = f"ERROR: {k}: {type(ex).__name__}: {ex}"
            errs.append(msg)
            eprint(msg)
    return ok, errs


def cmd_create_topics(admin: KafkaAdminClient, args) -> int:
    topics = args.topics or []
