    c.add_argument("topics", nargs="+")
    c.add_argument("--partitions", type=int, required=True)
    c.add_argument("--replication-factor", type=int, required=True)
    c.add_argument("--config", action="append", default=None, help="Topic config key=value (repeatable)")
    c.add_argument("--validate-only", action="store_true")

    d = sp.add_parser("delete-topics", help="Delete topics")
    d.add_argument("topics", nargs="+")

    dt = sp.add_parser("describe-topics", help="Describe topics (metadata)")
    dt.add_argument("topics", nargs="*", default=None)

    ip = sp.add_parser("increase-partitions", help="Increase partitions for topics")
    ip.add_argument("topics", nargs="+")
    ip.add_argument("--total-partitions", type=int, default=None, help="Target total partition count")
