    ip.add_argument("--assignment-json", default=None, help="JSON specifying replica assignment for new partitions")
    ip.add_argument("--validate-only", action="store_true")

    ac = sp.add_parser("alter-config", help="Alter topic configs (set/delete)")
    ac.add_argument("topics", nargs="+")
    ac.add_argument("--set", action="append", default=None, help="Set config key=value (repeatable)")
    ac.add_argument("--delete", action="append", default=None, help="Delete config key (repeatable)")
    ac.add_argument("--validate-only", action="store_true")

    dc = sp.add_parser("describe-config", help="Describe topic configs")
    dc.add_argument("topics", nargs="+")
    dc.add_argument("--include-synonyms", action="store_true")

    return p


